                      <th>Fee Paid (5%)</th>
                      <th>Current Bid</th>
                      <th>End Time</th>
                      <th>Status</th>
                      <th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {products.map(p => (
                      <tr key={p.id}>
                        <td>
                          <div className="d-flex align-items-center gap-3">
