      <AddProductModal onSuccess={fetchProducts} />

      {imageModalProduct && (
        <AddImagesModal
          product={imageModalProduct}
          onClose={() => setImageModalProduct(null)}
          onUploaded={fetchProducts}
        />
      )}
    </div>
  );
};

export default SellerDashboard;
